import React from 'react';
import './css/styles.css';
import {  BrowserRouter as Router, Switch, Route } from "react-router-dom";
import Urls from './components/classes/Urls';
import Header from './layouts/Header';
import Rapports from './components/rapports/Rapports';
import Commerciaux from './components/commerciaux/Commerciaux';
import Medecins from './components/medecins/Medecins'
import Orders from "./components/orders"
import Exits from "./components/exits"


class App extends React.Component {
  state={
    title:"Liste des rapports",
    urls:new Urls(),
    pays:[],
    user:{},
  }


  get_pays=async()=>{
    await fetch(this.state.urls.pays)
    .then(response=>response.json())
    .then((response)=>{
      this.setState({pays:response})
    })
  }

  get_user=async()=>{
    await fetch(this.state.urls.user)
    .then(response=>response.json())
    .then((response)=>{
      this.setState({user:response})
    })
  }

  change_title=(title)=>{
    this.setState({title})
  }

  componentDidMount(){
    this.get_pays();
    this.get_user();
  }

  render() {
    return (
      <React.Fragment>
      <Router>
        <Header title={this.state.title} user={this.state.user}/>
        <Switch>
          <Route exact path='/'> <Rapports  changeTitle={this.change_title} urls={this.state.urls} pays={this.state.pays}/> </Route>
          <Route exact path='/commerciaux'> <Commerciaux  changeTitle={this.change_title} urls={this.state.urls} pays={this.state.pays}/> </Route>
          <Route exact path='/medecins'> <Medecins  changeTitle={this.change_title} urls={this.state.urls} pays={this.state.pays}/> </Route>
          <Route exact path='/orders'> <Orders  changeTitle={this.change_title} urls={this.state.urls} pays={this.state.pays}/> </Route>
          {/* <Route exact path='/exits'> <Exits  changeTitle={this.change_title} urls={this.state.urls} pays={this.state.pays}/> </Route> */}

        </Switch>
      </Router>
      </React.Fragment>
    )
  }
}

export default App
