import React, {useState, useEffect} from 'react'
import DatePicker from "react-datepicker";


export default function Filters(props) {

    const today=new Date()

    const [selected_pays, setselected_pays] = useState(0);
    const [selected_wilaya, setselected_wilaya] = useState(0);
    const [selected_commune, setselected_commune] = useState(0);
    const [commercial, setcommercial] = useState("")
    const [produit, setproduit] = useState("")
    const [min_date, setmin_date] = useState(`${today.getFullYear()}-${today.getMonth()-1}-${today.getDate()}`)
    const [max_date, setmax_date] = useState(`${today.getFullYear()}-${today.getMonth()}-${today.getDate()}`)
    const [status, setstatus] = useState("")
    const [client, setclient] = useState("")


    const axios=require("axios")



    useEffect(() => {

        axios({
            url:props.urls.orders,
            params:{
                pay:selected_pays,
                wilaya:selected_wilaya,
                commune:selected_commune,
                commercial,
                produit,
                min_date,
                max_date,
                status,
                client,
            }
        })
        .then(res=>{
            console.log(res);
            props.setorders(res.data)
        })
        .catch(err=>{
                console.log(err)
        })

    }, [selected_pays,
        selected_wilaya,
        selected_commune,
        commercial,
        produit,
        min_date,
        max_date,
        status,
        client])
    
    const min_dateChange=date => {
        try{
          var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
          var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
        //   min_date_picker=date
          setmin_date(`${date.getFullYear()}-${month}-${day}`)
        }catch{
            setmin_date("")
        }
    
      };
      const max_dateChange=date => {
        try{
          var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
          var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
        //   max_date_picker=date
          setmax_date(`${date.getFullYear()}-${month}-${day}`)
        }catch{
            setmin_date("")
        }
      }

  return (
    <>
        <div className="py-4 container text-secondary">
            <div className="row">
            <div className="col-md pb-2">
                <b>Country:</b>
                <select className="form-control"
                onChange={(e)=>{setselected_pays(e.target.value);setselected_wilaya(0);setselected_commune(0);}}>
                <option value="0">Tous les pays</option>
                {props.pays.map(pys=>(
                    <option key={pys.id} value={pys.id} >{pys.nom}</option>
                ))}
                </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Wilaya:</b>
                    <select className="form-control"
                    onChange={(e)=>{setselected_wilaya(e.target.value);setselected_commune(0);}}>
                    <option value="0">Toutes les wilayas</option>
                    {props.pays.map(pys=>{
                    if((selected_pays==0) ||(selected_pays==pys.id))
                    return pys.wilayas_list.map(wilaya=>(
                        <option key={wilaya.id} value={wilaya.id}>{wilaya.nom}</option>
                    ))
                    })}
                    </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Commune:</b>
                    <select className="form-control"
                    onChange={(e)=>{setselected_commune(e.target.value)}}>
                    <option value="0">Toutes les communes</option>
                    {props.pays.map(pys=>{
                    if((selected_pays==0) ||(selected_pays==pys.id))
                    return pys.wilayas_list.map(wilaya=>{
                        if((selected_wilaya==0) ||(selected_wilaya==wilaya.id))
                        return wilaya.communes.map(commune=>(
                        <option key={commune.id} value={commune.id}>{commune.nom}</option>
                        ))
                    })
                    })}
                    </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Délégué:</b>
                    <select  className="form-control"
                    onChange={(e)=>{setcommercial(e.target.value)}}>
                    <option value=""> Tous</option>
                    {props.commerciaux.map(commercial=>{
                    if ((commercial.country==selected_pays)||(selected_pays==0))
                    return(
                        <option key={commercial.id} value={commercial.username}>{commercial.username}</option>
                        )
                    }
                    )}
                    </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Produit:</b>
                    <select type="text" className="form-control"
                    onChange={(e)=>{setproduit(e.target.value)
                    }}>
                    <option value=""> Tous</option>
                    {props.produits.map(produit=>{
                    if ((produit.pays.includes(parseInt(selected_pays)))||(selected_pays==0))
                    return(
                        <option key={produit.id} value={produit.id}>{produit.nom}</option>
                        )
                    }
                    )}
                    </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Date min:</b><br/>                                             
                    <DatePicker className="form-control"
                      selected={min_date!="" ? new Date(min_date.split("-")[0], min_date.split("-")[1], min_date.split("-")[2]) : new Date()} 
                      dateFormat="dd/MM/yyyy"
                      onChange={min_dateChange} 
                      required/>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Date max:</b><br/>                                      
                    <DatePicker className="form-control"
                       selected={max_date!="" ? new Date(max_date.split("-")[0], max_date.split("-")[1], max_date.split("-")[2]) : new Date()} 
                       onChange={max_dateChange}
                       dateFormat="dd/MM/yyyy"
                       required/>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Status:</b>
                    <select type="text" className="form-control"
                    onChange={(e)=>{setstatus(e.target.value)
                    }}>
                    <option value=""> Tous</option>
                    <option value="initial">initial</option>
                    <option value="traite">traite</option>
                    </select>
                </div>
                <div className="col-md-2 pb-2">
                    <b>Mot Clé:</b>
                    <input type="text"  onKeyUp={(e)=>setclient(e.target.value)} className="form-control"/>
                </div>


            </div>
        </div>
    </>
  )
}
